// ── RA-826: Format Qwen 3 14B prompt from stored intel entries ───────────────
const res     = $input.first().json;
const entries = (res.entries || []).slice(0, 20); // cap at 20 items for context window

if (entries.length === 0) {
  return [{
    json: {
      has_entries: false,
      system: '',
      user: '',
    }
  }];
}

const system = [
  'Produce a concise "Weekly Workspace Update" executive brief for the Pi-CEO Intelligence Report.',
  'Focus on: Gemini and AI capability changes, MCP or agent protocol updates, NotebookLM enhancements,',
  'Workspace automation and scheduling changes, pricing or policy shifts.',
  'Output 200–300 words. No filler words (delve, tapestry, landscape, leverage, robust, seamless, elevate).',
  'No first-person language. Bullet points for key items. End with a "Recommended Actions" section (max 3 items).',
].join(' ');

const itemLines = entries.map((e, i) =>
  `${i + 1}. ${e.title} (${(e.published || '').slice(0, 10)}): ${e.summary.slice(0, 300)}`
).join('\n');

const user = `Summarise these ${entries.length} Google Workspace updates into the weekly brief:\n\n${itemLines}`;

return [{ json: { has_entries: true, system, user, entry_count: entries.length } }];

// ── RA-826: Format Telegram message from Qwen response ───────────────────────
const ollamaRes = $input.first().json;
const brief     = (ollamaRes.message || {}).content || '';

if (!brief.trim()) {
  throw new Error('Qwen 3 14B returned empty brief — check Ollama is running and qwen3:14b is pulled');
}

const today = new Date().toLocaleDateString('en-AU', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric', timeZone: 'Australia/Sydney'
});

const message = `📋 *Weekly Workspace Intel*\n_${today}_\n\n${brief}\n\n_Source: workspaceupdates.googleblog.com via Pi-CEO RA-826_`;

// Telegram 4096-char limit — truncate with notice if needed
const maxLen = 4000;
const truncated = message.length > maxLen ? message.slice(0, maxLen) + '\n\n…_(truncated)_' : message;

return [{ json: { message: truncated } }];

const res = $input.first().json;
const ok  = res.ok === true;
if (!ok) {
  throw new Error(`Telegram sendMessage failed: ${JSON.stringify(res)}`);
}
console.log(`✅ Weekly Workspace brief sent via Telegram: message_id=${res.result?.message_id}`);
return [{ json: { success: true, message_id: res.result?.message_id } }];
